DROP TABLE IF EXISTS `proveedor`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `proveedor` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `fk_direccion` int unsigned NOT NULL,
  `nombre_comercial` varchar(65) COLLATE utf8mb4_unicode_ci NOT NULL,
  `razon_social` varchar(65) COLLATE utf8mb4_unicode_ci NOT NULL,
  `correo` varchar(254) COLLATE utf8mb4_unicode_ci NOT NULL,
  `telefono` varchar(15) COLLATE utf8mb4_unicode_ci NOT NULL,
  `estatus` enum('ACTIVO','INACTIVO') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'ACTIVO',
  `fecha_creacion` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `usuario_creacion` int unsigned NOT NULL,
  `fecha_movimiento` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `usuario_movimiento` int unsigned NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `correo` (`correo`),
  UNIQUE KEY `telefono` (`telefono`),
  KEY `fk_direccion` (`fk_direccion`),
  KEY `usuario_creacion` (`usuario_creacion`),
  KEY `usuario_movimiento` (`usuario_movimiento`),
  CONSTRAINT `proveedor_ibfk_1` FOREIGN KEY (`fk_direccion`) REFERENCES `direccion` (`id`),
  CONSTRAINT `proveedor_ibfk_2` FOREIGN KEY (`usuario_creacion`) REFERENCES `usuario` (`id`),
  CONSTRAINT `proveedor_ibfk_3` FOREIGN KEY (`usuario_movimiento`) REFERENCES `usuario` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
